// ==========================================
// BLOB SHAPE PRESET REGISTRY
// Loaded before animations.js — exposes window.BLOB_SHAPES
// ==========================================

// --- Vector Utilities ---

function normalize(v) {
    const len = Math.sqrt(v[0] * v[0] + v[1] * v[1] + v[2] * v[2]);
    if (len < 1e-10) return [0, 0, 1];
    return [v[0] / len, v[1] / len, v[2] / len];
}

function subtractVec(a, b) {
    return [a[0] - b[0], a[1] - b[1], a[2] - b[2]];
}

function lerpVec(a, b, t) {
    return [a[0] + (b[0] - a[0]) * t, a[1] + (b[1] - a[1]) * t, a[2] + (b[2] - a[2]) * t];
}

// --- Path Extrusion (planar-stable) ---
// For spines in the XY plane (z=0), uses a stable frame that never flips.
// normal = perpendicular to tangent within the XY plane
// binormal = [0, 0, 1] (always out-of-plane)

function pathExtrude(theta, phi, pathDef, baseRadius) {
    const { spine, radiusFn } = pathDef;
    const totalLen = spine.length - 1;
    const t = Math.max(0, Math.min(1, theta / Math.PI));
    const segF = t * totalLen;
    const segIdx = Math.min(Math.floor(segF), totalLen - 1);
    const segT = segF - segIdx;

    const p = lerpVec(spine[segIdx], spine[segIdx + 1], segT);

    // Tangent via finite difference
    const dt = 0.002;
    const tA = Math.max(0, t - dt) * totalLen;
    const tB = Math.min(1, t + dt) * totalLen;
    const idxA = Math.min(Math.floor(tA), totalLen - 1);
    const idxB = Math.min(Math.floor(tB), totalLen - 1);
    const pA = lerpVec(spine[idxA], spine[idxA + 1], tA - idxA);
    const pB = lerpVec(spine[idxB], spine[idxB + 1], tB - idxB);
    const tang = normalize(subtractVec(pB, pA));

    // Stable planar frame: normal is perpendicular to tangent in XY plane
    const nx = -tang[1];
    const ny = tang[0];
    // binormal is always Z-axis for planar spines
    const bx = 0, by = 0, bz = 1;

    const tubeR = radiusFn(t);

    return {
        x: (p[0] + tubeR * (Math.cos(phi) * nx + Math.sin(phi) * bx)) * baseRadius,
        y: (p[1] + tubeR * (Math.cos(phi) * ny + Math.sin(phi) * by)) * baseRadius,
        z: (p[2] + tubeR * (Math.cos(phi) * 0  + Math.sin(phi) * bz)) * baseRadius
    };
}

// --- Arbitrary Mesh Builder ---
// Generates tube geometry from a pathDef as {vertices, edges} buffer.
// Unlike the sphere-grid path extrusion, this produces its own topology
// so it can represent branching/non-spherical shapes faithfully.

function buildTubeMesh(pathDef, axialSegments, radialDivisions) {
    const { spine, radiusFn } = pathDef;
    const totalLen = spine.length - 1;
    const vertices = [];
    const edges = [];

    for (let i = 0; i <= axialSegments; i++) {
        const t = i / axialSegments;
        const segF = t * totalLen;
        const segIdx = Math.min(Math.floor(segF), totalLen - 1);
        const segT = segF - segIdx;
        const p = lerpVec(spine[segIdx], spine[segIdx + 1], segT);

        // Tangent via finite difference
        const dt = 0.002;
        const tA = Math.max(0, t - dt) * totalLen;
        const tB = Math.min(1, t + dt) * totalLen;
        const idxA = Math.min(Math.floor(tA), totalLen - 1);
        const idxB = Math.min(Math.floor(tB), totalLen - 1);
        const pA = lerpVec(spine[idxA], spine[idxA + 1], tA - idxA);
        const pB = lerpVec(spine[idxB], spine[idxB + 1], tB - idxB);
        const tang = normalize(subtractVec(pB, pA));

        // Stable planar frame
        const nx = -tang[1], ny = tang[0];
        const bx = 0, by = 0, bz = 1;

        const tubeR = radiusFn(t);
        const ringStart = vertices.length;

        for (let j = 0; j < radialDivisions; j++) {
            const angle = (j / radialDivisions) * Math.PI * 2;
            const cosA = Math.cos(angle);
            const sinA = Math.sin(angle);
            vertices.push({
                x: p[0] + tubeR * (cosA * nx + sinA * bx),
                y: -(p[1] + tubeR * (cosA * ny + sinA * by)),
                z: p[2] + tubeR * (cosA * 0  + sinA * bz)
            });

            // Ring edge (circumferential)
            const nextJ = (j + 1) % radialDivisions;
            edges.push([ringStart + j, ringStart + nextJ]);

            // Longitudinal edge (connect to previous ring)
            if (i > 0) {
                const prevRingStart = ringStart - radialDivisions;
                edges.push([prevRingStart + j, ringStart + j]);
            }
        }
    }

    return { vertices, edges };
}

// --- Composite Mesh Builder ---
// Combines multiple tube segments into a single mesh.
// Each segment is a {spine, radiusFn} pathDef, optionally with
// axialSegments/radialDivisions overrides.

function buildCompositeMesh(segments, defaultAxial, defaultRadial) {
    const allVertices = [];
    const allEdges = [];
    for (const seg of segments) {
        const offset = allVertices.length;
        const mesh = buildTubeMesh(seg, seg.axialSegments || defaultAxial, seg.radialDivisions || defaultRadial);
        for (const v of mesh.vertices) allVertices.push(v);
        for (const [i, j] of mesh.edges) allEdges.push([i + offset, j + offset]);
    }
    return { vertices: allVertices, edges: allEdges };
}

// --- Circle Spine Helper ---
// Generates a closed circular spine path for wheel/ring shapes.

function circleSpine(cx, cy, radius, numPoints) {
    const pts = [];
    for (let i = 0; i <= numPoints; i++) {
        const angle = (i / numPoints) * Math.PI * 2;
        pts.push([cx + radius * Math.cos(angle), cy + radius * Math.sin(angle), 0]);
    }
    return pts;
}

/**
 * Interpolate a 3D profile (array of [t, rho, z] tuples).
 * Returns {rho, z} at the given t.
 */
function lerpProfile3(profile, t) {
    if (t <= profile[0][0]) return { rho: profile[0][1], z: profile[0][2] };
    if (t >= profile[profile.length - 1][0]) {
        const last = profile[profile.length - 1];
        return { rho: last[1], z: last[2] };
    }
    for (let i = 1; i < profile.length; i++) {
        if (t <= profile[i][0]) {
            const [t0, r0, z0] = profile[i - 1];
            const [t1, r1, z1] = profile[i];
            const frac = (t - t0) / (t1 - t0);
            return {
                rho: r0 + (r1 - r0) * frac,
                z: z0 + (z1 - z0) * frac
            };
        }
    }
    const last = profile[profile.length - 1];
    return { rho: last[1], z: last[2] };
}

// Helper: profile shape oriented vertically (axis = y).
// Positive z in profile = UP on screen (negated for canvas y-down).
function profileGetPosition(profile, theta, phi, config) {
    const t = theta / Math.PI;
    const { rho, z: axisPos } = lerpProfile3(profile, t);
    const R = config.baseRadius;
    return {
        x: rho * R * Math.cos(phi),
        y: -axisPos * R,
        z: rho * R * Math.sin(phi)
    };
}

